class Solution(object):
    def maximumPopulation(self, logs):
        events = []
        for birth, death in logs:
            events.append((birth, 1))
            events.append((death, -1))
        events.sort()
        max_pop = 0
        curr_pop = 0
        max_year = 0
        for year, delta in events:
            curr_pop += delta
            if delta == 1 and curr_pop > max_pop:
                max_pop = curr_pop
                max_year = year
        return max_year
